---@class LStoryObjectCtrl
local LStoryObjectCtrl = LxClass("LStoryObjectCtrl",nil)

local LStoryObject = LxRequire("LApp.gameplay.StoryCopy.Object.LStoryObject")

function LStoryObjectCtrl:LStoryObjectCtrl(mgr)
    ---@type LStoryManager
    self._mgr = mgr

    --所有对象列表{LFightIdleObject,LFightIdleObject,...}
    ---@type LStoryObject[]
    self._objList = {}
    --当前对象列表{key=LFightIdleObject,key=LFightIdleObject,...}
    ---@type table<number,LStoryObject>
    self._objMap = {}

    --己方队伍
    ---@type LStoryObject[]
    self._teamAList = {}

    --敌方队伍
    ---@type LStoryObject[]
    self._teamBList = {}

    --npc
    ---@type LStoryObject[]
    self._teamMList ={}

    --运行标记
    self._isRunning = false
    --缓存

    self._cacheList = {}

    self._enemyIdx = 0

    --检测用模板
    self._heroBounds = Bounds(Vector3.zero,Vector3.zero)
    self._monBounds = Bounds(Vector3.zero,Vector3.zero)
    self._godBounds = Bounds(Vector3.zero,Vector3.zero)

    self._spinePoolMap = {}
end

function LStoryObjectCtrl:InitHeroData(heroAttackSpeed,moveSpeed,heroSizeOnHook,heroAttDisOnHookMap,jumpCD,heroAttSpeedUp)
    ---monAttackSpeed,heroAttackSpeed,moveSpeed,heroSizeOnHook,heroAttDisOnHookMap,monAttDisOnHookTbl,jumpCD,heroAttSpeedUp,monMoveArea,monStayTime,monSpeedRate
    self._heroAttackSpeed = heroAttackSpeed
    self._heroMoveSpeed = moveSpeed
    self._heroSizeOnHook = heroSizeOnHook
    self._heroAttDisOnHookMap = heroAttDisOnHookMap
    self._jumpCD = jumpCD
    self._heroAttSpeedUp = heroAttSpeedUp

end

function LStoryObjectCtrl:InitGodSkillData(godSkillRefId, godPickRange)
    local godSkillData = LFightIdleConst.CreateSkillData(godSkillRefId, true, 0)
    self._godSkillData = godSkillData
    self._godPickRange = godPickRange
    if godSkillData then
        local calcData = godSkillData:GetSkillCalcData()
        if calcData then
            calcData.bAlwaysCrit = true
        end
    end
end

function LStoryObjectCtrl:OnCheckGodSkill(time)
    if not self._godSkill then return end
    if not self._godSkill:OnRun(time) then
        self._godSkill:Destroy()
        self._godSkill = nil
    end
end

function LStoryObjectCtrl:ResetGodSkillInfo(leaderObj)
    if not leaderObj then return end
    if self._godSkill then
        self._godSkill:SetAtkObject(leaderObj)
    end

    if self._godSkillData then
        local commonSkillData = leaderObj:GetCommonSkill()
        if not commonSkillData then
            return
        end
        self._godSkillData.skillRateList = table.light_copy(commonSkillData.skillRateList or {}, {})
        self._godSkillData.effectType = commonSkillData.effectType

    end
end

---金手指范围攻击
function LStoryObjectCtrl:DoGodAttackBounds(pos)
    if self._godSkill then return end
    if not self._godSkillData then return end

    local leaderObj = self:GetLeaderObject()
    if not leaderObj then return end
    self:ResetGodSkillInfo(leaderObj)

    local pickx = pos.x
    local picky = pos.y
    local minx,maxx,miny,maxy = self:GetManager():GetCameraViewBounds()
    local centerX = (minx + maxx) / 2
    minx = centerX - 3.2
    maxx = centerX + 3.2

    if pickx > maxx or pickx < minx or picky < miny or picky > maxy then return end --点在屏幕外， 无效

    local range = self._godPickRange or 1

    local pickMinx = math.max(minx, pickx - range)
    local pickMaxx = math.min(maxx, pickx + range)
    local pickMiny = math.max(miny, picky - range)
    local pickMaxy = math.min(maxy, picky + range)

    local godBounds = self._godBounds
    godBounds:SetMinMax(Vector3(pickMinx, pickMiny, 0), Vector3(pickMaxx, pickMaxy))

    local teamList = self:GetOppositeTeamBySide(leaderObj:GetSide()) or {}

    local monBounds = Bounds(Vector3.zero, Vector3.zero)
    local monExtents = monBounds.extents
    local monCenter = monBounds.center
    local tarList = {}
    for k,obj in ipairs(teamList) do
        if obj:IsReady() and obj:IsLive() then
            local pos = obj:GetPosition()
            local bodyBounds = obj:GetBodyBounds()
            local offset = bodyBounds:GetCenter() + pos
            monCenter.x = offset.x
            monCenter.y = offset.y
            monExtents.x = bodyBounds.extents.x
            monExtents.y = bodyBounds.extents.y
            if monBounds:Intersects(godBounds) then
                table.insert(tarList, obj)
            end
        end
    end

    local tarLen = #tarList
    if tarLen == 0 then
        return
    end

    local isAiState  = self:IsAiState()
    if not isAiState then
        local tempList = {}
        for k,v in ipairs(tarList) do
            local objId = v:GetObjectKey()
            if  self:IsGoodAttackValid(objId) then
                table.insert(tempList,v)
            end
        end

        tarList = tempList
    end
    tarLen = #tarList
    if tarLen == 0 then
        return
    end

    local skillData = self._godSkillData
    local skill = LFightIdleSkill:New(leaderObj,skillData,self:GetManager())
    local speedUp = leaderObj:GetAttSpeedUp()
    skill:EnableSpeedUp(speedUp ~= 1 and speedUp > 0,leaderObj:GetAttSpeedUp())
    self._godSkill = skill

    --设置目标
    local calcData = skillData:GetSkillCalcData() or {}
    local targetNum = calcData.targetNum or 1

    if tarLen > targetNum then
        local tmpList = {}
        local leftLen = tarLen
        for i=1, targetNum do
            local rand = LFightIdleConst.RandInteger(leftLen)
            table.insert(tmpList,table.remove(tarList,rand))
            leftLen = leftLen - 1
        end
        tarList = tmpList
    end


    skill:SetTarList(tarList)
    skill:SetClickPos(pos)
    skill:Start()

    LxUiHelper.PlayAudioSoundName(LSoundConst.TRIGGER_ATTACK_MON)
end



