---@return LStoryObject
function LStoryObjectCtrl:MakeObject(objData)
    local eventId = objData.refId

    local atkSpeed = self._heroAttackSpeed
    local jumpCD = self._jumpCD
    local heroAttSpeedUp = self._heroAttSpeedUp



    local obj = LStoryObject:New(self._mgr)
    if obj:Create(self,eventId) then
        obj:SetAtkSpeed(atkSpeed)
        obj:SetAtkDis(self._heroAttDisOnHookMap[obj:GetLocationType()])
        --obj:SetScaleSize(self._heroSizeOnHook)
        obj:SetJumpCd(jumpCD)
        obj:SetAttSpeedUp(heroAttSpeedUp)

        self:AddObject(obj)
        obj:SetClickFun(function (...)
            self:OnClickObj(...)
        end)
        obj:StartLoadDp()
    else
        obj:Destroy()
    end

    return obj
end


function LStoryObjectCtrl:OnClickObj(objId)
    local isAiState = self:IsAiState()
    if not isAiState then
        if not self._clickValidList then
            return
        end
        if not self._clickValidList[objId] then
            return
        end
    end

    --local obj = self._objMap[objId]
    local pos = self:GetObjPos(objId)
    self:DoGodAttackBounds(pos)
end

function LStoryObjectCtrl:AddClickObjList(objId)
    if not self._clickValidList then
        self._clickValidList = {}
    end

    self._clickValidList[objId] = true
end

function LStoryObjectCtrl:IsGoodAttackValid(objId)
    if not self._clickValidList then
        return false
    end
    return self._clickValidList[objId]
end


---@param obj LStoryObject
function LStoryObjectCtrl:AddObject(obj)
    if(self._isRunning) then
        table.insert(self._cacheList,{true,obj})
        return true
    end

    local objKey = obj:GetObjectKey()
    local oldObj = self._objMap[objKey]
    if oldObj then
        error("duplicate BtIdleObject key="..objKey)
        return
    end

    self._objMap[objKey] = obj
    table.insert(self._objList,obj)

    local side = obj:GetSide()
    if side == LFightIdleConst.SIDE_B then
        table.insert(self._teamBList,obj)
    elseif side == LFightIdleConst.SIDE_A then
        table.insert(self._teamAList,obj)
    else
        table.insert(self._teamMList,obj)
    end

    return true
end

function LStoryObjectCtrl:RemoveObject(obj)
    if(self._isRunning) then
        table.insert(self._cacheList,{false,obj})
        return true
    end

    local objKey = obj:GetObjectKey()
    local oldObj = self._objMap[objKey]
    if not oldObj then
        return false
    end

    self._objMap[objKey] = nil
    table.removeidata(self._objList,obj)

    if(obj:GetSide() == LFightIdleConst.SIDE_B) then
        table.removeidata(self._teamBList,obj)
    else
        table.removeidata(self._teamAList,obj)
    end
    return true
end

function LStoryObjectCtrl:GetSpinePool()
    return gLGamePool:GetSimplePool(LPoolTagConst.TAG_SCENE_POOL)
end

function LStoryObjectCtrl:GetObjByKey(objKey)
    return self._objMap[objKey]
end


function LStoryObjectCtrl:OnRun(time)
    self._isRunning = true
    local objList = self._objList
    local delObj = {}
    for k,v in ipairs(objList) do
        if(not v:OnRun(time)) then
            table.insert(delObj,v)
        end
    end
    self._isRunning = false

    for k=#delObj,1,-1 do
        local obj = delObj[k]
        self:RemoveObject(obj)
        obj:Destroy()
    end

    local cache = self._cacheList
    self._cacheList = {}
    for k,v in ipairs(cache) do
        if v[1] then
            self:AddObject(v[2])
        else
            local obj = v[2]
            self:RemoveObject(obj)
            obj:Destroy()
        end
    end
    self:CheckHeroCollider()
    self:OnCheckGodSkill(time)
end


function LStoryObjectCtrl:CheckHeroCollider()
    local heroBounds = self._heroBounds
    local monBounds = self._monBounds
    local teamA = self._teamAList

    local heroCenter = heroBounds:GetCenter()
    local heroSize = heroBounds.extents
    local monCenter = monBounds:GetCenter()
    local monSize = monBounds.extents

    local teamB = self._teamBList

    local list = {}
    for k,v in ipairs(teamB) do
        if v:IsLive() and v:IsReady() then
            table.insert(list,v)
        end
    end

    local pos
    local bounds
    local bIntersect = false
    local dir
    local heroPos = Vector3.zero
    local minx = 0
    local maxx = 0
    local monBodyX = 0


    for k,hero in ipairs(teamA) do

        local canCollider = hero:CanCollider()
        if canCollider then
            pos = hero:GetPosition()
            local boardRefId = hero:GetBoardRefId()
            --bounds = hero:GetBodyBounds()
            --不整个赋值是因为，lua中verctor是一个table来的，引用，不是值 和c# 不一样
            --改里面的值，会生效
            --heroCenter.x = pos.x + bounds:GetCenter().x
            --heroCenter.y = pos.y + bounds:GetCenter().y
            --heroSize.x = bounds:GetSize().x * 0.5
            --heroSize.y = bounds:GetSize().y * 0.5

            heroPos.x = pos.x
            heroPos.y = pos.y
            bIntersect = false
            for m,mon in ipairs(list) do
                if boardRefId == mon:GetBoardRefId() then
                    pos = mon:GetPosition()
                    monBodyX = mon:GetBodyX()
                    minx = pos.x - monBodyX
                    maxx = pos.x + monBodyX

                    if heroPos.x >= minx and heroPos.x <= maxx then
                        local dis = pos.x - heroPos.x
                        if dis > 0 then
                            --怪物在右边，朝左边闪避
                            dir = LFightIdleConst.DIRECTION_LEFT
                        elseif dis < 0 then
                            --怪物在zuo边，朝右边闪避
                            dir = LFightIdleConst.DIRECTION_RIGHT
                        else
                            --相同位置 朝怪物的方向闪避 营造被推的效果
                            dir = mon:GetDirection()
                        end
                        bIntersect = true
                        break
                    end
                end
            end
            if bIntersect then
                if hero:IsCanCollider() then
                    hero:SetDogeDir(dir)
                    hero:GetAI():ChangeAction(LFightIdleConst.ACTION_DOGE)
                end
                hero:UpdateAlphaTwinkle(1,1,0.3,1.5,8)
            end
        end


    end
end

function LStoryObjectCtrl:GetOppositeTeamBySide(side)
    if side == LFightIdleConst.SIDE_A then
        return self._teamBList
    elseif side == LFightIdleConst.SIDE_B then
        return self._teamAList
    else
        return {}
    end
end

function LStoryObjectCtrl:GetTeamBySide(side)
    if side == LFightIdleConst.SIDE_A then
        return self._teamAList
    elseif side == LFightIdleConst.SIDE_B then
        return self._teamBList
    else
        return self._teamMList
    end
end

function LStoryObjectCtrl:RemoveObjectById(heroId)
    local obj = self:GetObjByKey(heroId)
    if not obj then
        return
    end
    self:RemoveObject(obj)
    obj:Destroy()
end

function LStoryObjectCtrl:StartAllAI()
    self._isAiState = true
    for k,v in pairs(self._objMap) do
        if v and v:IsReady() then
            v:StartAi()
        end
    end
end

function LStoryObjectCtrl:StopAllAI()
    self._isAiState = false
    for k,v in pairs(self._objMap) do
        if v and v:IsReady() then
            v:StopAi()
        end
    end
end

function LStoryObjectCtrl:IsAiState()
    return self._isAiState
end

function LStoryObjectCtrl:TimePause()
    for k,v in pairs(self._objMap) do
        v:TimePause()
    end
end

function LStoryObjectCtrl:TimeResume()
    for k,v in pairs(self._objMap) do
        v:TimeResume()
    end
end

-----------------------------------------------------------------
function LStoryObjectCtrl:Destroy()
    local objList = self._objList
    if(objList) then
        for k,v in ipairs(self._objList) do
            v:Destroy()
        end
        self._objList = nil
    end

    gLGamePool:ClearSimplePool(LPoolTagConst.TAG_SCENE_POOL)

    table.removeall(self)
end

function LStoryObjectCtrl:GetObjPos(objId)
    local obj = self._objMap[objId]
    if obj and obj:IsReady() then
        local tran = obj:GetDisplayTrans()
        local topNodePos = obj:GetTopNodePos()
        local centerPosY = topNodePos.y + tran.position.y
        return Vector3.New(tran.position.x,centerPosY/2,tran.position.z)
    end
    return Vector3.zero
end

