function LStoryObjectCtrl:OnTouchStart(pos)
    self._bTouchStart = true
    self._touchStartPos = pos
    self._touchStartTime = self:GetTime()
    --print(tostring(pos).." ____________ touchstart")
end

function LStoryObjectCtrl:OnTouchMove(pos)

end

function LStoryObjectCtrl:OnTouchEnd(pos)
    if self._bTouchStart then
        self._bTouchStart = false
        local disTime = self:GetTime() - self._touchStartTime
        if disTime < 0.2 and Vector2.Magnitude(pos - self._touchStartPos) < 1 then
            self:DoGodAttackBounds(pos)
        end
        --print(tostring(pos).." ____________ OnTouchEnd len="..Vector2.Magnitude(pos - self._touchStartPos).." time="..disTime)
    end
end
function LStoryObjectCtrl:OnTouchCancel()
    self._bTouchStart = false
end

function LStoryObjectCtrl:GetTime()
    return self._mgr:GetTime()
end

function LStoryObjectCtrl:OnObjDead(objId)
    if not self._deadList then
        self._deadList = {}
    end
    self._deadList[objId] = true
end

function LStoryObjectCtrl:IsObjDead(objId)
    if not self._deadList then
        return false
    end
    return self._deadList[objId]
end

